mapper.select:
SELECT uc.*, ct.template_id as template_templateId, ct.name as template_name, ct.description as template_description, ct.coupon_type as template_couponType, ct.discount_amount as template_discountAmount, ct.min_order_amount as template_minOrderAmount FROM user_coupon uc LEFT JOIN coupon_template ct ON uc.template_id = ct.template_id WHERE uc.member_id = #{memberId}
AND uc.status = #{status}
ORDER BY uc.receive_time DESC
